// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract Web3Messenger {
    struct Message {
        address sender;
        address recipient;
        string text;
        uint256 timestamp;
    }

    mapping(bytes32 => Message[]) private conversations;

    event MessageSent(
        address indexed sender,
        address indexed recipient,
        uint256 timestamp
    );

    event ChatDiscovered(
        address indexed user,
        address indexed peer
    );

    function _chatKey(address a, address b) private pure returns (bytes32) {
        return a < b ? keccak256(abi.encodePacked(a, b)) : keccak256(abi.encodePacked(b, a));
    }

    function sendMessage(address recipient, string calldata text) external {
        require(recipient != address(0), "Invalid recipient");
        require(recipient != msg.sender, "Cannot message yourself");
        require(bytes(text).length > 0, "Empty message");

        bytes32 key = _chatKey(msg.sender, recipient);
        conversations[key].push(Message({
            sender: msg.sender,
            recipient: recipient,
            text: text,
            timestamp: block.timestamp
        }));

        emit MessageSent(msg.sender, recipient, block.timestamp);
        emit ChatDiscovered(msg.sender, recipient);
        emit ChatDiscovered(recipient, msg.sender);
    }

    function messageCount(address a, address b) external view returns (uint256) {
        return conversations[_chatKey(a, b)].length;
    }

    function getConversation(
        address userA,
        address userB,
        uint256 startIndex,
        uint256 count
    ) external view returns (Message[] memory, uint256 total) {
        bytes32 key = _chatKey(userA, userB);
        Message[] storage msgs = conversations[key];
        total = msgs.length;

        if (startIndex >= total) {
            return (new Message[](0), total);
        }

        uint256 end = startIndex + count;
        if (end > total) end = total;
        uint256 len = end - startIndex;

        Message[] memory result = new Message[](len);
        for (uint256 i = 0; i < len; i++) {
            result[i] = msgs[startIndex + i];
        }

        return (result, total);
    }

    function getLatestMessages(
        address userA,
        address userB,
        uint256 count
    ) external view returns (Message[] memory, uint256 total) {
        bytes32 key = _chatKey(userA, userB);
        Message[] storage msgs = conversations[key];
        total = msgs.length;

        if (total == 0) {
            return (new Message[](0), 0);
        }

        uint256 start = total > count ? total - count : 0;
        uint256 len = total - start;

        Message[] memory result = new Message[](len);
        for (uint256 i = 0; i < len; i++) {
            result[i] = msgs[start + i];
        }

        return (result, total);
    }
}
